import { aggiornaReview } from "@italian-oss-legal-platform/backend";
import { NextResponse } from "next/server";

export const runtime = "nodejs";

interface RouteContext {
  params: Promise<{
    id: string;
  }>;
}

interface UpdateReviewRequest {
  assegnataA?: string;
  decisione?: string;
  motivo?: string;
  operatore?: string;
  stato?: string;
}

export async function PATCH(request: Request, context: RouteContext) {
  const params = await context.params;
  const id = safeDecode(params.id);
  const rawBody = await request.text();
  const backendResponse = await proxyBackend(`/review/queue/${encodeURIComponent(id)}`, {
    body: rawBody,
    headers: request.headers,
    method: "PATCH"
  });

  if (backendResponse) {
    return backendResponse;
  }

  const result = await aggiornaReview(
    id,
    parseJson<UpdateReviewRequest>(rawBody),
    process.env,
    tokenOperatore(request.headers)
  );
  return NextResponse.json(result.body, { status: result.status });
}

async function proxyBackend(
  path: string,
  init: { body: string; headers: Headers; method: "PATCH" }
): Promise<NextResponse | null> {
  const baseUrl = process.env.BACKEND_API_URL?.trim();

  if (!baseUrl) {
    return null;
  }

  const token = tokenOperatore(init.headers);
  const headers: Record<string, string> = {
    "content-type": "application/json"
  };

  if (token) {
    headers["x-admin-token"] = token;
  }

  const response = await fetch(`${baseUrl.replace(/\/+$/g, "")}${path}`, {
    body: init.body,
    headers,
    method: init.method
  });

  return NextResponse.json(await response.json(), { status: response.status });
}

function tokenOperatore(headers: Headers): string | undefined {
  const value = headers.get("x-admin-token") ?? headers.get("authorization");
  return value?.replace(/^Bearer\s+/i, "").trim() || undefined;
}

function parseJson<T>(rawBody: string): T | null {
  try {
    return JSON.parse(rawBody) as T;
  } catch {
    return null;
  }
}

function safeDecode(value: string): string {
  try {
    return decodeURIComponent(value);
  } catch {
    return value;
  }
}
